import React, { useState } from 'react';

function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch('http://127.0.0.1:5000/api/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: email, password: password }),
      });

      const result = await response.json();

      if (response.ok) {
        localStorage.setItem("email_aktif", email);
        localStorage.setItem("nama_aktif", result.user);
        alert("Login Berhasil! Selamat Datang " + result.user);
        window.location.href = "/dashboard";
      } else {
        alert(result.message || "Email atau Password Salah");
      }
    } catch (error) {
      console.error("Error Login:", error);
      alert("Gagal terhubung ke Backend. Pastikan Flask sudah jalan!");
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.loginCard}>
        {/* --- SISI KIRI: INFORMASI --- */}
        <div style={styles.leftSection}>
          <h1 style={styles.brandTitle}>SMART BIN</h1>
          <p style={styles.brandSubtitle}>
            SISTEM MONITORING DAN PENGELOLAAN <br />
            TEMPAT SAMPAH PINTAR BERBASIS IOT
          </p>

          <div style={styles.illustration}>
            {/* */}
            <img 
              src="6cf1cdfe8436573f885588a15073dabd" 
              alt="illustration" 
              style={{ width: '80%' }} 
            />
          </div>

          <div style={styles.footerText}>
            <p>Program Studi Informatika</p>
            <p>Fakultas Ilmu Komputer</p>
            <p>Mia ferdi akson.</p>
          </div>
        </div>

        {/* --- SISI KANAN: FORM LOGIN --- */}
        <div style={styles.rightSection}>
          <h2 style={styles.loginHeader}>LOGIN</h2>
          <form onSubmit={handleLogin} style={styles.form}>
            <div style={styles.inputWrapper}>
              <span style={styles.icon}>👤</span>
              <input
                type="email"
                placeholder="Email Address"
                style={styles.input}
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
              />
            </div>

            <div style={styles.inputWrapper}>
              <span style={styles.icon}>🔒</span>
              <input
                type="password"
                placeholder="Kata sandi"
                style={styles.input}
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
              />
            </div>

            <button type="submit" style={styles.button}>Masuk</button>
          </form>

          <div style={styles.signupBox}>
             <p style={{ fontSize: '13px', color: '#666' }}>Belum punya akun?</p>
             <a href="/register" style={styles.signupLink}>Daftar Admin Baru</a>
          </div>

          <p style={styles.versionTag}>SMART BIN 2026</p>
        </div>
      </div>
    </div>
  );
}

